document.addEventListener("DOMContentLoaded",function(){const formCadastro=document.getElementById("form-cadastro");const planoSelect=document.getElementById("plano");const treinadorSelect=document.getElementById("treinador");const modalidadeInput=document.getElementById("modalidade");const periodicidadeSelect=document.getElementById("periodicidade");const currentPage=window.location.pathname;let modalidade="";if(currentPage.includes("corrida.html")){modalidade="corrida"}else if(currentPage.includes("multisport.html")){modalidade="multisport"}if(modalidadeInput){modalidadeInput.value=modalidade}const treinadores={corrida:{essencial:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando","Guto Fernandes"],premium:["Bruno Jeremias","Jéssica Rodrigues","Thais Prando","Elinai Freitas","Guto Fernandes"]},multisport:{essencial:["Jéssica Rodrigues","Thais Prando"],premium:["Jéssica Rodrigues","Thais Prando","Elinai Freitas","Guto Fernandes"]}};function atualizarTreinadores(){if(!treinadorSelect)return;treinadorSelect.innerHTML='<option value="">Selecione um treinador</option>';const planoCompleto=planoSelect.value;let tipoPlano="";if(planoCompleto.includes("essencial")){tipoPlano="essencial"}else if(planoCompleto.includes("premium")){tipoPlano="premium"}if(modalidade&&tipoPlano&&treinadores[modalidade]&&treinadores[modalidade][tipoPlano]){const treinadoresDisponiveis=treinadores[modalidade][tipoPlano];treinadoresDisponiveis.forEach(treinador=>{const option=document.createElement("option");option.value=treinador.toLowerCase().replace(/\s+/g,"-");option.textContent=treinador;if(tipoPlano==="premium"&&(treinador==="Elinai Freitas"||treinador==="Guto Fernandes")){option.classList.add("premium-exclusive")}treinadorSelect.appendChild(option)})}}function atualizarPeriodicidade(){if(!periodicidadeSelect)return;periodicidadeSelect.innerHTML='<option value="">Selecione a periodicidade</option>';const planoCompleto=planoSelect.value;const periodicidades=[{valor:"mensal",texto:"Mensal"},{valor:"trimestral",texto:"Trimestral"},{valor:"semestral",texto:"Semestral (Melhor custo-benefício)"}];periodicidades.forEach(periodicidade=>{const option=document.createElement("option");option.value=periodicidade.valor;option.textContent=periodicidade.texto;if(planoCompleto.includes(periodicidade.valor)){option.selected=true}if(periodicidade.valor==="semestral"){option.classList.add("melhor-opcao")}periodicidadeSelect.appendChild(option)})}if(planoSelect){planoSelect.addEventListener("change",function(){atualizarTreinadores();atualizarPeriodicidade()});atualizarTreinadores();atualizarPeriodicidade()}if(formCadastro){formCadastro.addEventListener("submit",function(event){event.preventDefault();const planoSelecionado=planoSelect.value;const treinadorSelecionado=treinadorSelect?treinadorSelect.value:"";const periodicidadeSelecionada=periodicidadeSelect?periodicidadeSelect.value:"";const checkoutUrl=`#checkout?plano=${planoSelecionado}&treinador=${treinadorSelecionado}&periodicidade=${periodicidadeSelecionada}`;alert(`Formulário enviado com sucesso!\n\nModalidade: ${modalidade}\nPlano: ${planoSelecionado}\nTreinador: ${treinadorSelecionado}\nPeriodicidade: ${periodicidadeSelecionada}\n\nEm um ambiente de produção, o usuário seria redirecionado para: ${checkoutUrl}`)})}});